import UIKit
import Capacitor
import WebKit

@objc(RebrandBridgeViewController)
class RebrandBridgeViewController: CAPBridgeViewController {

    private var webViewBottom: NSLayoutConstraint?
    private var keyboardHeight: CGFloat = 0

    override func capacitorDidLoad() {
        super.capacitorDidLoad()
        guard let webView = bridge?.webView else { return }
        let userScript = WKUserScript(
            source: Self.rebrandJS,
            injectionTime: .atDocumentStart,
            forMainFrameOnly: true
        )
        webView.configuration.userContentController.addUserScript(userScript)
        webView.evaluateJavaScript(Self.rebrandJS, completionHandler: nil)

        // No constraint manipulation — let Capacitor manage the WebView frame.
        // Keyboard avoidance is handled via JS injection (sets compose.style.bottom = kbHeight px).

        NotificationCenter.default.addObserver(
            self, selector: #selector(handleKeyboardChange(_:)),
            name: UIResponder.keyboardWillChangeFrameNotification, object: nil
        )
        NotificationCenter.default.addObserver(
            self, selector: #selector(handleKeyboardHide(_:)),
            name: UIResponder.keyboardWillHideNotification, object: nil
        )
        NotificationCenter.default.addObserver(
            self, selector: #selector(handleKeyboardDidHide(_:)),
            name: UIResponder.keyboardDidHideNotification, object: nil
        )
    }

    @objc private func handleKeyboardDidHide(_ note: Notification) {
        guard let webView = bridge?.webView else { return }
        keyboardHeight = 0
        webView.evaluateJavaScript("(function(){try{var s=['.compose','.chat-composer','.composer','.chat-input-bar','[data-bottom-bar]'];s.forEach(function(q){document.querySelectorAll(q).forEach(function(e){e.style.bottom='0px';});});document.body.classList.remove('kb-open');}catch(e){}})();", completionHandler: nil)
    }

    deinit {
        NotificationCenter.default.removeObserver(self)
    }

    @objc private func handleKeyboardChange(_ note: Notification) {
        guard let webView = bridge?.webView,
              let frameValue = note.userInfo?[UIResponder.keyboardFrameEndUserInfoKey] as? NSValue
        else { return }
        let kbFrameInView = view.convert(frameValue.cgRectValue, from: nil)
        let intersection = view.bounds.intersection(kbFrameInView)
        let h = intersection.isNull ? 0 : intersection.height
        if abs(h - keyboardHeight) < 0.5 { return }
        keyboardHeight = h
        // Inject inline style on the chat composer + global CSS var.
        // position:fixed bottom:<h>px puts the bar h pixels above viewport bottom = above keyboard.
        let js = """
        (function(){try{
          var h = \(Int(h));
          document.documentElement.style.setProperty('--kb-h', h + 'px');
          document.body.style.setProperty('--kb-h', h + 'px');
          if (h > 0) document.body.classList.add('kb-open'); else document.body.classList.remove('kb-open');
          var sels = ['.compose', '.chat-composer', '.composer', '.chat-input-bar', '[data-bottom-bar]'];
          for (var i = 0; i < sels.length; i++) {
            var els = document.querySelectorAll(sels[i]);
            for (var j = 0; j < els.length; j++) {
              els[j].style.position = 'fixed';
              els[j].style.bottom = h + 'px';
              els[j].style.transition = 'bottom 0.2s ease';
            }
          }
          var el = document.activeElement;
          if (el && (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.isContentEditable)) {
            setTimeout(function(){ try { el.scrollIntoView({block:'center', behavior:'smooth'}); } catch(e){} }, 220);
          }
        }catch(e){}})();
        """
        webView.evaluateJavaScript(js, completionHandler: nil)
    }

    @objc private func handleKeyboardHide(_ note: Notification) {
        guard let webView = bridge?.webView else { return }
        keyboardHeight = 0
        let js = """
        (function(){try{
          document.documentElement.style.setProperty('--kb-h','0px');
          document.body.style.setProperty('--kb-h','0px');
          document.body.classList.remove('kb-open');
          var sels = ['.compose', '.chat-composer', '.composer', '.chat-input-bar', '[data-bottom-bar]'];
          for (var i = 0; i < sels.length; i++) {
            var els = document.querySelectorAll(sels[i]);
            for (var j = 0; j < els.length; j++) { els[j].style.bottom = '0px'; }
          }
        }catch(e){}})();
        """
        webView.evaluateJavaScript(js, completionHandler: nil)
    }

    static let rebrandJS = """
    (function() {
      // --- Safe-area top fix: ensures dashboard chrome doesn't render under the iOS status bar ---
      try {
        // 1) Make sure viewport-fit=cover is set so env(safe-area-inset-*) actually returns values.
        var vp = document.querySelector('meta[name="viewport"]');
        if (vp && vp.content.indexOf('viewport-fit=cover') === -1) {
          vp.content = vp.content + ', viewport-fit=cover';
        } else if (!vp) {
          vp = document.createElement('meta');
          vp.name = 'viewport';
          vp.content = 'width=device-width, initial-scale=1, viewport-fit=cover';
          document.head && document.head.appendChild(vp);
        }
        // 2) Inject a style tag that pushes the top chrome below the status bar.
        //    Covers: in-flow body padding, common header/nav selectors, fixed-position top elements.
        function injectSafeAreaCSS() {
          if (document.getElementById('linkher-safe-area-css')) return;
          var s = document.createElement('style');
          s.id = 'linkher-safe-area-css';
          s.textContent = [
            ':root{--safe-top:env(safe-area-inset-top);--safe-bottom:env(safe-area-inset-bottom)}',
            'body{padding-top:max(env(safe-area-inset-top), 0px)}',
            'header, .header, .app-header, .top-bar, .topbar, .navbar, [role="banner"], [data-top-bar]{padding-top:max(env(safe-area-inset-top), 0px)}',
            '.fixed-top, [data-fixed-top]{top:max(env(safe-area-inset-top), 0px) !important}',
            // Nuke any pseudo-element that would render "SafeTea" via content:
            '[class*="safetea" i]::before, [class*="safetea" i]::after, [id*="safetea" i]::before, [id*="safetea" i]::after { content: "" !important; display: none !important; }'
          ].join('\n');
          (document.head || document.documentElement).appendChild(s);
        }
        if (document.readyState === 'loading') {
          document.addEventListener('DOMContentLoaded', injectSafeAreaCSS);
        } else {
          injectSafeAreaCSS();
        }
      } catch(e) {}

      var ALESSIA_HTML_B64 = '';
      window.ALESSIA_ASSETS = JSON.parse('{"futuristic":"data:image/jpeg;base64,","warm_human":"data:image/jpeg;base64,","guardian":"data:image/jpeg;base64,","professional":"data:image/jpeg;base64,","soft_anime":"data:image/jpeg;base64,","minimal_android":"data:image/jpeg;base64,","avatar_default":"data:image/jpeg;base64,"}');

      if (window.__linkherRebrandLoaded) return;
      window.__linkherRebrandLoaded = true;

      // === Save-to-Vault Share Extension deep-link handler ===
      // The Share Extension copies the shared file into the App Group's
      // shared inbox, then opens the host app via
      //   app.linkher.mobile://save-to-vault?uri=<path>&name=<n>&mime=<m>
      // Capacitor App.appUrlOpen fires here. We stash the metadata in
      // sessionStorage and navigate to /save-to-vault.html, which already
      // has the upload code path the web Share Target uses.
      try {
        function bindShareDeepLink() {
          if (window.__linkherShareDeepLinkBound) return;
          var Cap = window.Capacitor;
          if (!Cap || !Cap.Plugins || !Cap.Plugins.App) return false;
          window.__linkherShareDeepLinkBound = true;
          Cap.Plugins.App.addListener('appUrlOpen', function (data) {
            try {
              var raw = data && data.url; if (!raw) return;
              var u = new URL(raw);
              var proto = String(u.protocol || '').toLowerCase();
              if (proto !== 'app.linkher.mobile:' && proto !== 'safetea:') return;
              if (String(u.hostname || '').toLowerCase() !== 'save-to-vault') return;
              var pending = {
                filePath: u.searchParams.get('uri') || '',
                name: u.searchParams.get('name') || 'shared-file',
                mime: u.searchParams.get('mime') || '',
                source: 'ios_share_extension',
                ts: Date.now(),
              };
              try { sessionStorage.setItem('ios_share_pending', JSON.stringify(pending)); } catch (e) {}
              window.location.href = '/save-to-vault.html';
            } catch (e) { /* malformed URL — silent */ }
          });
          return true;
        }
        if (!bindShareDeepLink()) {
          var shareTries = 0;
          var shareIv = setInterval(function () {
            shareTries++;
            if (shareTries > 30 || bindShareDeepLink()) clearInterval(shareIv);
          }, 1000);
        }
      } catch (e) {}

      // === iOS push-notification device-token registration ===
      // PC's commit (dd0684c) shipped /api/push/register-token. This block runs
      // once per session: waits for the Capacitor PushNotifications plugin to
      // become available + the user to be logged in, requests permissions,
      // registers, and POSTs the APNs token to the backend so server-side
      // pushes can target this device. Idempotent — backend UPSERTs by user_id
      // and this script no-ops if the token hasn't changed since last register.
      try {
        var TOKEN_LSK = 'safetea_token';
        var LAST_PUSH_LSK = 'linkher_last_apns_push_token';
        function tryRegisterPush() {
          if (window.__linkherPushRegistering) return;
          var Capacitor = window.Capacitor;
          if (!Capacitor || !Capacitor.Plugins || !Capacitor.Plugins.PushNotifications) return;
          var jwt = null;
          try { jwt = localStorage.getItem(TOKEN_LSK); } catch (e) {}
          if (!jwt) return; // user not logged in yet — try again later
          window.__linkherPushRegistering = true;
          var PN = Capacitor.Plugins.PushNotifications;
          PN.removeAllListeners && PN.removeAllListeners();
          PN.addListener('registration', function (ev) {
            try {
              var token = ev && (ev.value || ev.token);
              if (!token) return;
              var prev = null;
              try { prev = localStorage.getItem(LAST_PUSH_LSK); } catch (e) {}
              if (prev === token) return; // already registered same token
              fetch('/api/push/register-token', {
                method: 'POST',
                headers: { 'Authorization': 'Bearer ' + jwt, 'Content-Type': 'application/json' },
                body: JSON.stringify({ token: token, platform: 'ios' })
              }).then(function (r) {
                if (r.ok) { try { localStorage.setItem(LAST_PUSH_LSK, token); } catch (e) {} }
              }).catch(function () { /* offline / transient — try again next session */ });
            } catch (e) {}
          });
          PN.addListener('registrationError', function () { /* user denied or APNs unreachable — silent */ });
          PN.requestPermissions().then(function (res) {
            if (res && res.receive === 'granted') { PN.register(); }
          }).catch(function () {});
        }
        // Try immediately, then poll briefly until Capacitor + JWT are both ready.
        tryRegisterPush();
        var pushTries = 0;
        var pushIv = setInterval(function () {
          pushTries++;
          if (pushTries > 30 || window.__linkherPushRegistering) { clearInterval(pushIv); return; }
          tryRegisterPush();
        }, 1000);
      } catch (e) {}

      // === Alessia (LinkHer AI Companion) ===
      // 1) If the user has navigated to /alessia, replace the document with the
      //    bundled Alessia SPA decoded from base64 above. This lets us serve a
      //    fully iOS-only feature without modifying getsafetea.app.
      // 2) Inject an Alessia tile into the dashboard's tools grid so the
      //    feature is discoverable from the main app (iOS-only — this user
      //    script doesn't run on web/Android).
      try {
        if (location.pathname === '/alessia' || location.pathname === '/alessia.html') {
          var html;
          try { html = atob(ALESSIA_HTML_B64); } catch (e) { html = ''; }
          if (html) {
            // Defer until after document is ready to receive document.write
            var paint = function () {
              try {
                document.open();
                document.write(html);
                document.close();
              } catch (e) {
                document.documentElement.innerHTML = html;
              }
            };
            if (document.readyState === 'loading') {
              document.addEventListener('DOMContentLoaded', paint);
            } else {
              paint();
            }
            return; // Stop the rest of the rebrand script from running on Alessia.
          }
        }
      } catch (e) {}


      // Keyboard-aware input focus: when the user taps a text field, scroll it
      // into view so the active input is never hidden behind the keyboard.
      // Belt-and-braces for screens that don't naturally resize with the WKWebView.
      try {
        document.addEventListener('focusin', function (e) {
          var t = e && e.target;
          if (!t) return;
          var tag = (t.tagName || '').toLowerCase();
          var editable = t.isContentEditable;
          if (tag !== 'input' && tag !== 'textarea' && tag !== 'select' && !editable) return;
          setTimeout(function () {
            try { t.scrollIntoView({ block: 'center', behavior: 'smooth' }); } catch (e) {}
          }, 280);
        }, true);
      } catch (e) {}

      function injectAlessiaTile() {
        try {
          var grid = document.querySelector('.tools-grid');
          if (!grid || grid.querySelector('[data-alessia-tile]')) return;
          var tile = document.createElement('a');
          tile.setAttribute('data-alessia-tile', '1');
          tile.className = 'tools-grid-cell';
          tile.href = '/alessia';
          tile.setAttribute('aria-label', 'Alessia. AI protector and companion');
          tile.innerHTML =
            '<div class="tools-grid-icon" style="background:linear-gradient(135deg,rgba(255,107,168,0.25),rgba(155,89,182,0.25));box-shadow:0 0 14px rgba(255,107,168,0.35)">' +
              '<i class="fa-solid fa-shield-heart" style="color:#FF6BA8"></i>' +
            '</div>' +
            '<div class="tools-grid-title">Alessia ' +
              '<span style="font-size:9px;font-weight:800;letter-spacing:0.6px;padding:2px 6px;background:linear-gradient(135deg,#FF6BA8,#9B59B6);color:#fff;border-radius:4px;margin-left:4px;vertical-align:1px">LinkHer+</span>' +
            '</div>' +
            '<div class="tools-grid-desc">Your AI protector</div>';
          grid.insertBefore(tile, grid.firstChild);
        } catch (e) {}
      }


      // Vault upload fix: jsdelivr's +esm bundle (used by vault-folder.html for
      // @vercel/blob/client) emits root-relative sub-imports like
      // /npm/is-node-process@1.2.0/+esm. From getsafetea.app's origin those 404
      // and the dynamic import throws "importing module script failed". Inject
      // an import map at document start so the relative path resolves to the
      // jsdelivr CDN. Requires iOS 16.4+ (WKWebView import-map support).
      try {
        if (HTMLScriptElement.supports && HTMLScriptElement.supports('importmap')) {
          var im = document.createElement('script');
          im.type = 'importmap';
          im.textContent = '{"imports":{"/npm/":"https://cdn.jsdelivr.net/npm/"}}';
          var firstChild = (document.head || document.documentElement).firstChild;
          if (firstChild) (document.head || document.documentElement).insertBefore(im, firstChild);
          else (document.head || document.documentElement).appendChild(im);
        }
      } catch (e) {}


      var LOGO = 'data:image/png;base64,';

      function looksLikeLogo(img) {
        var src = (img.getAttribute('src') || img.currentSrc || '').toLowerCase();
        var alt = (img.getAttribute('alt') || '').toLowerCase();
        var cls = ((img.className && typeof img.className === 'string') ? img.className : '').toLowerCase();
        var id  = (img.id || '').toLowerCase();
        return src.indexOf('logo') !== -1
            || src.indexOf('safetea') !== -1
            || src.indexOf('linkher') !== -1
            || src.indexOf('brand') !== -1
            || (src.indexOf('icon') !== -1 && src.indexOf('icon-') !== -1)
            || alt.indexOf('safetea') !== -1
            || alt.indexOf('linkher') !== -1
            || alt.indexOf('logo') !== -1
            || cls.indexOf('logo') !== -1
            || cls.indexOf('brand') !== -1
            || id.indexOf('logo') !== -1;
      }

      // Containers that almost always hold a top-of-screen brand mark
      var HEADER_SEL = 'header, nav, .header, .app-header, .top-bar, .topbar, .navbar, .nav-bar, .site-header, .page-header, .toolbar, .appbar, [role="banner"], [data-top-bar]';

      function isInHeader(el) {
        try {
          var node = el;
          while (node && node !== document.body) {
            if (node.matches && node.matches(HEADER_SEL)) return true;
            node = node.parentElement;
          }
        } catch(e) {}
        return false;
      }

      function rebrandImages(root) {
        var scope = root || document;
        // Split strategy:
        //   in-header logos (covered by overlay) → hide
        //   outside-header logos → swap src to LinkHer so we don't leave empty slots
        var imgs = scope.querySelectorAll('img');
        for (var i = 0; i < imgs.length; i++) {
          var img = imgs[i];
          // Always sanitize alt regardless of other treatment.
          if (img.alt && img.alt.indexOf('SafeTea') !== -1) {
            img.alt = img.alt.replace(/SafeTea/g, 'LinkHer');
          }
          if (img.dataset && img.dataset.linkherRebranded) continue;
          var inHdr = isInHeader(img);
          var likeLogo = looksLikeLogo(img);
          if (inHdr) {
            img.style.display = 'none';
            if (img.dataset) img.dataset.linkherRebranded = '1';
            continue;
          }
          if (likeLogo) {
            img.src = LOGO;
            img.removeAttribute('srcset');
            img.removeAttribute('sizes');
            if (img.dataset) img.dataset.linkherRebranded = '1';
          }
        }
        // Hide inline SVGs >= 32px inside header containers (likely brand marks; small ones are icons).
        var svgs = scope.querySelectorAll(HEADER_SEL + ' svg');
        for (var j = 0; j < svgs.length; j++) {
          var sv = svgs[j];
          if (sv.dataset && sv.dataset.linkherRebranded) continue;
          var rect = sv.getBoundingClientRect();
          if (rect.width < 32 || rect.height < 32) continue;
          sv.style.display = 'none';
          if (sv.dataset) sv.dataset.linkherRebranded = '1';
        }
        // Hide CSS background-image logos in header containers.
        var bgCandidates = scope.querySelectorAll(HEADER_SEL + ' *');
        for (var k = 0; k < bgCandidates.length; k++) {
          var node = bgCandidates[k];
          if (node.dataset && node.dataset.linkherRebranded) continue;
          var cs; try { cs = window.getComputedStyle(node); } catch(e) { continue; }
          var bg = cs && cs.backgroundImage;
          if (!bg || bg === 'none') continue;
          var lower = bg.toLowerCase();
          if (lower.indexOf('logo') === -1 && lower.indexOf('safetea') === -1 && lower.indexOf('linkher') === -1 && lower.indexOf('brand') === -1) continue;
          node.style.backgroundImage = 'none';
          if (node.dataset) node.dataset.linkherRebranded = '1';
        }
      }

      // Inject a LinkHer-branded top bar over every screen. Idempotent + safe-area aware.
      function injectLinkHerHeader() {
        if (document.getElementById('linkher-overlay-header')) return;
        if (!document.body) return;
        var bar = document.createElement('div');
        bar.id = 'linkher-overlay-header';
        bar.style.cssText = [
          'position:fixed', 'top:0', 'left:0', 'right:0',
          'z-index:2147483646',
          'background:linear-gradient(180deg,#0a0518 0%,#12082a 100%)',
          'box-shadow:0 1px 0 rgba(255,107,168,0.18), 0 2px 12px rgba(0,0,0,0.4)',
          'padding-top:env(safe-area-inset-top)',
          'display:flex','align-items:center','justify-content:center',
          'pointer-events:none'
        ].join(';') + ';';
        var img = document.createElement('img');
        img.src = LOGO;
        img.alt = 'LinkHer';
        img.style.cssText = 'height:34px;width:auto;margin:8px 0;display:block;';
        bar.appendChild(img);
        document.body.appendChild(bar);
        // Reserve space so the page content isn't covered by the overlay.
        function reserve() {
          var h = bar.getBoundingClientRect().height;
          document.body.style.paddingTop = h + 'px';
          document.documentElement.style.setProperty('--linkher-header-h', h + 'px');
        }
        // Initial + on-rotation
        setTimeout(reserve, 0);
        window.addEventListener('resize', reserve);
      }

      function rebrandText(root) {
        var node = root || document.body;
        function walk(rootNode) {
          if (!rootNode) return;
          var walker = document.createTreeWalker(rootNode, NodeFilter.SHOW_TEXT, null);
          var n;
          while ((n = walker.nextNode())) {
            if (n.nodeValue && n.nodeValue.indexOf('SafeTea') !== -1) {
              n.nodeValue = n.nodeValue.replace(/SafeTea/g, 'LinkHer');
            }
          }
          // Shadow DOM
          var allEls = rootNode.querySelectorAll ? rootNode.querySelectorAll('*') : [];
          for (var i = 0; i < allEls.length; i++) {
            if (allEls[i].shadowRoot) walk(allEls[i].shadowRoot);
          }
        }
        walk(node);
        // Same-origin iframe content
        try {
          var iframes = (root || document).querySelectorAll('iframe');
          for (var f = 0; f < iframes.length; f++) {
            try {
              var doc = iframes[f].contentDocument;
              if (doc && doc.body) walk(doc.body);
            } catch(e) {}
          }
        } catch(e) {}

        // Document title
        if (document.title && document.title.indexOf('SafeTea') !== -1) {
          document.title = document.title.replace(/SafeTea/g, 'LinkHer');
        }
        // Meta tags (og:title, og:site_name, description, twitter:title, etc.)
        try {
          var metas = document.querySelectorAll('meta[content*="SafeTea"]');
          for (var m = 0; m < metas.length; m++) {
            var c = metas[m].getAttribute('content');
            if (c) metas[m].setAttribute('content', c.replace(/SafeTea/g, 'LinkHer'));
          }
        } catch(e) {}
        // attribute scan: aria-label, placeholder, title, value, alt, data-*
        try {
          var attrEls = (root || document).querySelectorAll('[aria-label*="SafeTea"], [placeholder*="SafeTea"], [title*="SafeTea"], [value*="SafeTea"], [alt*="SafeTea"]');
          for (var i = 0; i < attrEls.length; i++) {
            var el = attrEls[i];
            ['aria-label','placeholder','title','value','alt'].forEach(function(a){
              var v = el.getAttribute(a);
              if (v && v.indexOf('SafeTea') !== -1) el.setAttribute(a, v.replace(/SafeTea/g, 'LinkHer'));
            });
            // also scan data-* attrs
            for (var ai = 0; ai < el.attributes.length; ai++) {
              var att = el.attributes[ai];
              if (att.name.indexOf('data-') === 0 && att.value && att.value.indexOf('SafeTea') !== -1) {
                el.setAttribute(att.name, att.value.replace(/SafeTea/g, 'LinkHer'));
              }
            }
          }
        } catch(e) {}
      }

      var pending = false;
      function rebrandSoon() {
        if (pending) return;
        pending = true;
        setTimeout(function() {
          pending = false;
          injectLinkHerHeader();
          rebrandImages();
          rebrandText();
          injectAlessiaTile();
        }, 50);
      }

      function start() {
        injectLinkHerHeader();
        rebrandImages();
        rebrandText();
        injectAlessiaTile();
        try {
          new MutationObserver(function() { rebrandSoon(); }).observe(
            document.documentElement,
            { childList: true, subtree: true, characterData: true }
          );
        } catch (e) {}
      }

      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', start);
      } else {
        start();
      }
    })();
    """
}
